// Get input data
const inputData = $input.all();
const outputData = [];

// Process each input item
for (const item of inputData) {
  const data = item.json;
  const replication = data.gen_params.repetition;
  const initialSeed = data.gen_params.seed;

  // Replicate the structure n times with incremented seed
  for (let i = 0; i < replication; i++) {
    const replicated = JSON.parse(JSON.stringify(data)); // Deep copy
    replicated.gen_params.seed = initialSeed + i;
    outputData.push({ json: replicated });
  }
}

return outputData;
